INSERT INTO /*RateMapper.insertServiceAlterTrace 서비스 변경 이력 저장  */
   MCP_SERVICE_ALTER_TRACE (
      NCN                      --New 계약번호
    , CONTRACT_NUM             --계약번호
    , SEQ                      --일련번호
    , GLOBAL_NO
    , SUBSCRIBER_NO            --전화번호 CTN
    , EVENT_CODE               --이벤트 코드
    , PRCS_MDL_IND             --처리 모듈 구분
    , TRTM_RSLT_SMST           --호출 내용
    , PRCS_SBST                --처리 결과 내용
    , RSLT_CD                  --처리결과코드
    , A_SOC_CODE               --이전 코드 값
    , T_SOC_CODE               --이후 코드 값
    , A_SOC_AMNT               --변경전 요금제 할인 월정액
    , T_SOC_AMNT               --변경후 요금제 할인 월정액
    , PARAMETER                --인자값 설정값
    , ACCESS_IP                --접속 IP
    , ACCESS_URL               --REFERER URL
    , USER_ID                  --아이디
    , SYS_DT                   --등록일
    , SYS_RDATE                --등록일시
) VALUES (
      #{ncn}
    , #{contractNum}
    , (SELECT NVL(MAX(SEQ), 0)+1 FROM MCP_SERVICE_ALTER_TRACE WHERE NCN=#{ncn} AND SYS_DT = TO_CHAR(SYSDATE, 'YYYYMMDD'))
    , #{globalNo}
    , #{subscriberNo}
    , #{eventCode}
    , #{prcsMdlInd}
    , #{trtmRsltSmst}
    , #{prcsSbst}
    , #{rsltCd}
    , #{aSocCode}
    , #{tSocCode}
    , #{aSocAmnt}
    , #{tSocAmnt}
    , #{parameter}
    , #{accessIp}
    , #{accessUrl}
    , #{userId}
    , TO_CHAR(SYSDATE, 'YYYYMMDD')
    , SYSDATE
)
